import { gzipSync } from 'fflate'
import { postWithBigPayload } from './_internal/big-payloads'
import type { AuthResolver } from './auth'
import type { Logger } from './logger'
import { decompressResultField, gzipAndEncode, serializeToKebab } from './utils'

/**
 * Best-effort extraction of HTTP status code from an error caught around an
 * `HttpClient` call. Used by service classes to populate the `statusCode`
 * field of typed `*ServiceError`s. Falls back to 0 (matches Python SDK's
 * `_status_code_from_exc`) when the error isn't HTTP-shaped.
 */
export function extractStatusCode(err: unknown): number {
  if (err && typeof err === 'object') {
    const e = err as { status?: unknown; statusCode?: unknown; response?: { status?: unknown } }
    if (typeof e.statusCode === 'number') return e.statusCode
    if (typeof e.status === 'number') return e.status
    if (e.response && typeof e.response.status === 'number') return e.response.status
  }
  if (err instanceof Error) {
    // Error messages from this module use the format `HTTP <code>: ...`
    const match = err.message.match(/HTTP\s+(\d{3})/)
    if (match) return Number(match[1])
  }
  return 0
}

/**
 * Best-effort extraction of HTTP response body. Returns `''` when not
 * available — matches Python SDK's `_response_body_from_exc` fallback.
 */
export function extractResponseBody(err: unknown): string {
  if (err && typeof err === 'object') {
    const e = err as { responseBody?: unknown; response?: { text?: unknown; body?: unknown } }
    if (typeof e.responseBody === 'string') return e.responseBody
    if (e.response) {
      if (typeof e.response.body === 'string') return e.response.body
      if (typeof e.response.text === 'string') return e.response.text
    }
  }
  return err instanceof Error ? err.message : ''
}

/**
 * Parse a `Retry-After` header value to seconds. Returns `null` for an absent,
 * non-numeric, or negative value. Only the delta-seconds form is supported
 * (the HTTP-date form is not parsed — matching `computeRetryDelay`). Shared by
 * the retry loop and by callers that surface `Retry-After` on typed errors.
 */
export function parseRetryAfter(value: string | null): number | null {
  if (value === null) return null
  const n = Number(value)
  return Number.isFinite(n) && n >= 0 ? n : null
}

/** Best-effort extraction of a `Retry-After` hint (seconds) from a caught
 * error. Reads the `retryAfter` property attached by `HttpError`. */
export function extractRetryAfter(err: unknown): number | null {
  if (err && typeof err === 'object') {
    const e = err as { retryAfter?: unknown }
    if (typeof e.retryAfter === 'number') return e.retryAfter
  }
  return null
}

/**
 * Error thrown by `fetchWithRetry` on a non-retryable / retries-exhausted HTTP
 * status. Carries the structured `statusCode` / `responseBody` / `retryAfter`
 * so service-layer catch blocks can build typed `*ServiceError`s without
 * scraping the message. Message keeps the `HTTP <code>: <body>` format for
 * back-compat with existing `extractStatusCode` regex callers.
 */
export class HttpError extends Error {
  public readonly statusCode: number
  public readonly responseBody: string
  public readonly retryAfter: number | null
  constructor(statusCode: number, responseBody: string, retryAfter: number | null) {
    super(`HTTP ${statusCode}: ${responseBody}`)
    this.name = 'HttpError'
    this.statusCode = statusCode
    this.responseBody = responseBody
    this.retryAfter = retryAfter
  }
}

/** Default timeout for HTTP requests (3 minutes) */
const DEFAULT_TIMEOUT = 180000

/** Default max retries */
const DEFAULT_MAX_RETRIES = 2

/** Backoff constants matching Python SDK: base=2, cap=10, floor=0.5s */
const BACKOFF_BASE = 2
const BACKOFF_CAP = 10
const BACKOFF_FLOOR_S = 0.5

/** HTTP status codes considered retryable */
const RETRYABLE_STATUS_CODES = new Set([429, 500, 502, 503, 504])

/** Request configuration passed to interceptors */
export interface RequestConfig {
  url: string
  method: string
  headers: Record<string, string>
  body?: string | ArrayBuffer | Uint8Array
  /** External abort signal to cancel the request. */
  signal?: AbortSignal
}

/** Interceptor hooks for request/response lifecycle */
export interface HttpInterceptors {
  /** Called before the request is sent. Can modify the config. */
  onRequest?: (config: RequestConfig) => RequestConfig | Promise<RequestConfig>
  /** Called after a successful response. */
  onResponse?: (response: Response) => void | Promise<void>
  /** Called when a request fails (after all retries exhausted). */
  onError?: (error: Error) => void | Promise<void>
}

export interface HttpClientConfig {
  /**
   * Auth header resolver. Called per request — `getToken` callers refresh
   * JWTs without rebuilding the client, env var changes propagate, etc.
   */
  getAuthHeaders: AuthResolver
  /** Base URL for the API */
  baseUrl: string
  /** Logger instance */
  logger: Logger
  /** Request timeout in milliseconds. Default: 180000 (3 minutes) */
  timeout?: number
  /** Maximum number of retries for retryable errors. Default: 2 */
  maxRetries?: number
  /** Request/response interceptor hooks */
  interceptors?: HttpInterceptors
  /**
   * Big-payload runtime config — bare gateway URL for `/uploads/presign`
   * plus the auto-switching kill-switch and threshold. The kill-switch and
   * threshold are passed as **getters** so they're re-resolved on every
   * call: notebook / Worker users that flip
   * `INFRARED_BIG_PAYLOADS_ENABLED` mid-session see the new value
   * immediately. Snapshotting once at construction violated the
   * documented runtime contract.
   */
  gatewayBaseUrl?: string
  getBigPayloadEnabled?: () => boolean
  getBigPayloadThresholdBytes?: () => number
}

export class HttpClient {
  private getAuthHeaders: AuthResolver
  private baseUrl: string
  private logger: Logger
  private timeout: number
  private maxRetries: number
  private interceptors: HttpInterceptors
  private gatewayBaseUrl?: string
  private getBigPayloadEnabled: () => boolean
  private getBigPayloadThresholdBytes: () => number

  constructor(config: HttpClientConfig) {
    this.getAuthHeaders = config.getAuthHeaders
    this.baseUrl = config.baseUrl
    this.logger = config.logger
    this.timeout = config.timeout ?? DEFAULT_TIMEOUT
    this.maxRetries = config.maxRetries ?? DEFAULT_MAX_RETRIES
    this.interceptors = config.interceptors ?? {}
    this.gatewayBaseUrl = config.gatewayBaseUrl
    this.getBigPayloadEnabled = config.getBigPayloadEnabled ?? (() => true)
    this.getBigPayloadThresholdBytes =
      config.getBigPayloadThresholdBytes ?? (() => 5 * 1024 * 1024)
  }

  /**
   * POST request with optional gzip compression.
   *
   * `options.bigPayload`: when `true`, requests with serialized JSON bytes
   * exceeding the configured threshold automatically switch to the `$ref`
   * envelope flow (presign → S3 PUT → envelope POST). Below the threshold,
   * or when the kill switch is off, the call uses the inline path with
   * existing retry/backoff. Mutually exclusive with `compress` — gzip is
   * for the legacy text/plain control-plane path; big-payloads use a
   * different wire shape.
   */
  async post<T = any>(
    path: string,
    data: any,
    options: {
      compress?: boolean
      serializeNames?: boolean
      decompressResult?: boolean
      /** External abort signal to cancel the request. */
      signal?: AbortSignal
      /** Route through big-payload `$ref` envelope above threshold. */
      bigPayload?: boolean
      /**
       * Gzip the JSON body with a standard `Content-Encoding: gzip` header
       * (raw gzip bytes — NOT the legacy base64 `compress` convention). The
       * gateway gunzips transparently. Geometry compresses ~18×, keeping large
       * bodies small enough to send inline and sidestepping the (server-side
       * unsupported on these endpoints) `$ref` envelope. Mutually exclusive
       * with `compress` / `bigPayload`.
       */
      gzip?: boolean
    } = {},
  ): Promise<T> {
    const url = `${this.baseUrl}${path}`
    this.logger.debug({ event: 'http_request', method: 'POST', url })

    // Resolve auth headers per request — `getToken` resolves live, env
    // var flips propagate without a rebuild.
    const headers: Record<string, string> = { ...(await this.getAuthHeaders()) }

    let body: string | ArrayBuffer | Uint8Array
    const shouldSerialize = options.serializeNames ?? true
    const payload = shouldSerialize ? serializeToKebab(data) : data

    if (options.compress) {
      const jsonData = JSON.stringify(payload)
      const compressed = gzipAndEncode(jsonData)
      headers['Content-Type'] = 'text/plain'
      headers['X-Content-Encoding'] = 'gzip'
      headers['X-Infrared-Encoding'] = 'gzip'
      body = compressed
    } else if (options.gzip) {
      // Standard Content-Encoding: gzip (raw bytes) — the gateway gunzips.
      headers['Content-Type'] = 'application/json'
      headers['Content-Encoding'] = 'gzip'
      body = gzipSync(new TextEncoder().encode(JSON.stringify(payload)))
    } else {
      headers['Content-Type'] = 'application/json'
      body = JSON.stringify(payload)
    }

    // Big-payload routing — only kicks in when the caller opted in
    // (`bigPayload: true`) AND the gateway URL is configured AND the
    // payload is plain JSON (not gzip). Wrap the inline call in
    // `postWithBigPayload`: under threshold it executes the closure
    // unchanged (existing fetchWithRetry semantics intact), over
    // threshold it routes through presign → S3 PUT → `$ref` POST.
    if (options.bigPayload && this.gatewayBaseUrl && !options.compress && !options.gzip) {
      // Resolve big-payload knobs at call time so env-var flips
      // propagate (matches CLAUDE.md "read on every call" contract).
      const json = await postWithBigPayload<any>({
        url,
        body: payload as Record<string, unknown>,
        authHeaders: { ...headers },
        gatewayBaseUrl: this.gatewayBaseUrl,
        thresholdBytes: this.getBigPayloadThresholdBytes(),
        enabled: this.getBigPayloadEnabled(),
        envelopeTimeoutMs: this.timeout,
        signal: options.signal,
        logger: this.logger,
        inline: () =>
          this.fetchWithRetry({
            url,
            method: 'POST',
            headers,
            body,
            signal: options.signal,
          }),
        parseEnvelope: (resp) => {
          if (!resp.ok) {
            throw new Error(`HTTP ${resp.status}: ${resp.bodyText}`)
          }
          return resp.bodyJson ?? undefined
        },
      })
      if (options.decompressResult) {
        return decompressResultField(json as any, this.logger) as T
      }
      return json as T
    }

    const json = await this.fetchWithRetry({
      url,
      method: 'POST',
      headers,
      body,
      signal: options.signal,
    })

    if (options.decompressResult) {
      return decompressResultField(json as any, this.logger) as T
    }

    return json as T
  }

  /**
   * DELETE request
   */
  async delete<T = any>(path: string): Promise<T | undefined> {
    const url = `${this.baseUrl}${path}`
    this.logger.debug({ event: 'http_request', method: 'DELETE', url })

    const headers: Record<string, string> = { ...(await this.getAuthHeaders()) }

    const json = await this.fetchWithRetry({ url, method: 'DELETE', headers })
    return json as T
  }

  /**
   * GET request
   */
  async get<T = any>(path: string, params?: Record<string, any>): Promise<T> {
    const url = new URL(`${this.baseUrl}${path}`)

    if (params) {
      Object.entries(params).forEach(([key, value]) => {
        if (value !== undefined && value !== null) {
          url.searchParams.append(key, String(value))
        }
      })
    }

    const urlString = url.toString()
    this.logger.debug({ event: 'http_request', method: 'GET', url: urlString })

    const headers: Record<string, string> = { ...(await this.getAuthHeaders()) }

    return await this.fetchWithRetry({ url: urlString, method: 'GET', headers })
  }

  /**
   * Execute an HTTP request with retry logic.
   *
   * Retry strategy (matching Python SDK):
   * - Retryable status codes: 429, 500, 502, 503, 504
   * - Exponential backoff with full jitter: random(0, min(cap, base * 2^attempt))
   * - Floor: max(floor, computed_delay)
   * - Retry-After header support (always wins over computed backoff)
   * - Configurable max retries (default: 2)
   */
  private async fetchWithRetry(config: RequestConfig): Promise<any> {
    let attempt = 0

    while (true) {
      // Apply request interceptor
      let effectiveConfig = config
      if (this.interceptors.onRequest) {
        effectiveConfig = await this.interceptors.onRequest({ ...config })
      }

      // Set up timeout with AbortController, chained with external signal
      const controller = new AbortController()
      const timeoutId = setTimeout(() => controller.abort(), this.timeout)

      // If an external signal is provided, abort when it fires
      const externalSignal = effectiveConfig.signal
      let externalAbortHandler: (() => void) | undefined
      if (externalSignal) {
        if (externalSignal.aborted) {
          clearTimeout(timeoutId)
          const abortError = new Error('Request aborted by external signal')
          abortError.name = 'AbortError'
          throw abortError
        }
        externalAbortHandler = () => controller.abort()
        externalSignal.addEventListener('abort', externalAbortHandler, { once: true })
      }

      let response: Response
      try {
        response = await fetch(effectiveConfig.url, {
          method: effectiveConfig.method,
          headers: effectiveConfig.headers,
          // Cast for Uint8Array bodies (gzip) — TS's BodyInit narrows it out,
          // but every target runtime accepts a Uint8Array body at runtime.
          body: effectiveConfig.body as unknown as BodyInit,
          signal: controller.signal,
        })
        clearTimeout(timeoutId)
      } catch (error) {
        clearTimeout(timeoutId)
        if (externalSignal && externalAbortHandler) {
          externalSignal.removeEventListener('abort', externalAbortHandler)
        }

        // Distinguish external abort from timeout
        if (error instanceof Error && error.name === 'AbortError') {
          if (externalSignal?.aborted) {
            const abortError = new Error('Request aborted by external signal')
            abortError.name = 'AbortError'
            if (this.interceptors.onError) {
              await this.interceptors.onError(abortError)
            }
            throw abortError
          }
          const timeoutError = new Error(`Request timed out after ${this.timeout}ms`)
          this.logger.error({ event: 'http_timeout', timeoutMs: this.timeout })

          if (this.interceptors.onError) {
            await this.interceptors.onError(timeoutError)
          }

          throw timeoutError
        }

        // Network errors (TypeError from fetch) are retryable
        if (error instanceof TypeError && attempt < this.maxRetries) {
          const delay = this.computeRetryDelay(attempt)
          this.logger.warn({
            event: 'http_retry',
            error: String(error),
            attempt: attempt + 1,
            maxRetries: this.maxRetries,
            delayMs: Math.round(delay * 1000),
          })
          await sleep(delay * 1000)
          attempt++
          continue
        }

        if (error instanceof Error && this.interceptors.onError) {
          await this.interceptors.onError(error)
        }

        this.logger.error({ event: 'http_request_failed', error: String(error) })
        throw error
      }

      // Clean up external abort listener now that fetch completed
      if (externalSignal && externalAbortHandler) {
        externalSignal.removeEventListener('abort', externalAbortHandler)
      }

      // Response received -- handle status codes outside the try/catch
      // so that thrown HTTP errors don't trigger the network error handler
      if (!response.ok) {
        const errorText = await response.text()

        // Check if retryable
        if (RETRYABLE_STATUS_CODES.has(response.status) && attempt < this.maxRetries) {
          const delay = this.computeRetryDelay(attempt, response)
          this.logger.warn({
            event: 'http_retry',
            status: response.status,
            attempt: attempt + 1,
            maxRetries: this.maxRetries,
            delayMs: Math.round(delay * 1000),
          })
          await sleep(delay * 1000)
          attempt++
          continue
        }

        // Non-retryable or retries exhausted. Throw a typed HttpError carrying
        // the structured status/body/Retry-After so service catch blocks can
        // surface them (e.g. WeatherServiceError.retryAfter) without scraping
        // the message.
        const error = new HttpError(
          response.status,
          errorText,
          parseRetryAfter(response.headers.get('Retry-After')),
        )
        this.logger.error({ event: 'http_error', status: response.status, body: errorText })

        if (this.interceptors.onError) {
          await this.interceptors.onError(error)
        }

        throw error
      }

      // Apply response interceptor
      if (this.interceptors.onResponse) {
        await this.interceptors.onResponse(response.clone())
      }

      // Handle empty responses (e.g. 204 No Content from DELETE)
      if (response.status === 204) {
        return undefined
      }

      // Read body as text first to distinguish empty from malformed
      if (typeof response.text === 'function') {
        const text = await response.text()
        if (!text || !text.trim()) {
          return undefined
        }
        try {
          return JSON.parse(text)
        } catch {
          throw new Error(
            `HTTP ${response.status}: response body is not valid JSON: ${text.slice(0, 200)}`,
          )
        }
      }

      // Fallback for environments where text() is not available (e.g. test mocks)
      return await response.json()
    }
  }

  /**
   * Compute retry delay with full jitter, matching Python SDK.
   *
   * Priority:
   * 1. Retry-After header (if present) -- always wins
   * 2. Full jitter: random(0, min(cap, base * 2^attempt))
   * 3. Floor: max(backoff_floor, computed_delay)
   */
  private computeRetryDelay(attempt: number, response?: Response): number {
    // Check Retry-After header (always wins if present and valid)
    if (response) {
      const retryAfter = parseRetryAfter(response.headers.get('Retry-After'))
      if (retryAfter !== null) return retryAfter
    }

    // Full jitter: random(0, min(cap, base * 2^attempt))
    const maxDelay = Math.min(BACKOFF_CAP, BACKOFF_BASE * 2 ** attempt)
    const jitter = Math.random() * maxDelay
    return Math.max(BACKOFF_FLOOR_S, jitter)
  }
}

/** Sleep for the given number of milliseconds */
function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms))
}
